Assets::Assets() 
    : partition_(nullptr), mmap_root_(nullptr), mmap_handle_(0) {
    // Initialize assets partition mapping
    if (!InitializePartition()) {
        ESP_LOGE(TAG, "Failed to initialize assets partition");
        return;
    }

    // Validate basic structure using magic header
    const uint8_t* header = reinterpret_cast<const uint8_t*>(mmap_root_);
    if (header[0] != 'A' || header[1] != 'S' || header[2] != 'T' || header[3] != 'S') {
        ESP_LOGE(TAG, "Invalid assets partition header");
        return;
    }

    // Parse metadata: number of files, total length, checksum
    uint32_t stored_files = *(uint32_t*)(mmap_root_ + 4);
    uint32_t stored_len = *(uint32_t*)(mmap_root_ + 8);
    uint32_t stored_chksum = *(uint32_t*)(mmap_root_ + 12);

    // Checksum validation
    uint32_t calculated_checksum = CalculateChecksum(mmap_root_ + 16, stored_len);
    if (calculated_checksum != stored_chksum) {
        ESP_LOGE(TAG, "Checksum mismatch: expected 0x%lx, got 0x%lx", stored_chksum, calculated_checksum);
        return;
    }

    // Populate assets lookup table
    size_t offset = 16 + stored_files * sizeof(mmap_assets_table);
    for (uint32_t i = 0; i < stored_files; ++i) {
        auto item = reinterpret_cast<const mmap_assets_table*>(mmap_root_ + 16 + i * sizeof(mmap_assets_table));
        std::string name(item->asset_name);
        Asset asset{
            .size = static_cast<size_t>(item->asset_size),
            .offset = offset
        };
        assets_[name] = asset;
        offset += item->asset_size;
    }

    ESP_LOGI(TAG, "Assets initialized successfully with %lu entries", assets_.size());
}

