bool InitializePartition() {
    const char* TAG = "Assets";

    // Step 1: Find the assets partition
    const esp_partition_t* partition = esp_partition_find_first(
        ESP_PARTITION_TYPE_DATA,
        ESP_PARTITION_SUBTYPE_ANY,
        "assets"
    );
    if (partition == NULL) {
        ESP_LOGE(TAG, "Failed to find assets partition");
        return false;
    }

    // Optional: Validate partition size here if needed
    if (partition->size == 0) {
        ESP_LOGE(TAG, "Invalid partition size");
        return false;
    }

    // Step 2: Map the partition into memory
    esp_partition_mmap_handle_t mmap_handle;
    const void* mapped_memory;
    esp_err_t err = esp_partition_mmap(
        partition,
        0,
        partition->size,
        SPI_FLASH_MMAP_DATA,
        &mapped_memory,
        &mmap_handle
    );
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to map partition to memory: %s", esp_err_to_name(err));
        return false;
    }

    // Step 3: Perform checksum validation (example assumes first 4 bytes are checksum)
    const uint8_t* data_ptr = (const uint8_t*)mapped_memory;
    uint32_t stored_checksum = *((const uint32_t*)data_ptr);
    uint32_t calculated_checksum = CalculateChecksum(
        (const char*)(data_ptr + sizeof(uint32_t)),
        partition->size - sizeof(uint32_t)
    );

    if (stored_checksum != calculated_checksum) {
        ESP_LOGE(TAG, "Checksum mismatch: stored=0x%04X, calculated=0x%04X",
                 stored_checksum, calculated_checksum);
        esp_partition_munmap(mmap_handle);
        return false;
    }

    // Step 4: Parse metadata and build asset index
    cJSON* root = cJSON_Parse((char*)(data_ptr + sizeof(uint32_t)));
    if (root == NULL) {
        ESP_LOGE(TAG, "Failed to parse assets JSON");
        esp_partition_munmap(mmap_handle);
        return false;
    }

    cJSON* assets_array = cJSON_GetObjectItem(root, "assets");
    if (!cJSON_IsArray(assets_array)) {
        ESP_LOGE(TAG, "Assets array missing or invalid");
        cJSON_Delete(root);
        esp_partition_munmap(mmap_handle);
        return false;
    }

    assets_.clear(); // Clear any previous entries

    for (int i = 0; i < cJSON_GetArraySize(assets_array); i++) {
        cJSON* item = cJSON_GetArrayItem(assets_array, i);

        cJSON* name_item = cJSON_GetObjectItem(item, "name");
        cJSON* size_item = cJSON_GetObjectItem(item, "size");
        cJSON* offset_item = cJSON_GetObjectItem(item, "offset");

        if (!cJSON_IsString(name_item) || !cJSON_IsNumber(size_item) || !cJSON_IsNumber(offset_item)) {
            ESP_LOGW(TAG, "Skipping invalid asset entry at index %d", i);
            continue;
        }

        std::string name = name_item->valuestring;
        size_t size = size_item->valueint;
        size_t offset = offset_item->valueint;

        assets_[name] = {size, offset};
    }

    cJSON_Delete(root);

    // Store handle for later unmapping
    mmap_handle_ = mmap_handle;
    partition_ = partition;

    ESP_LOGI(TAG, "Asset partition initialized successfully with %d assets", assets_.size());
    return true;
}

