bool Assets::Apply() {
    // Ensure previous mapping is released if exists
    if (mmap_handle_) {
        esp_err_t err = esp_partition_munmap(mmap_handle_);
        if (err != ESP_OK) {
            ESP_LOGE(TAG, "Failed to unmap previous assets partition: %s", esp_err_to_name(err));
            return false;
        }
        mmap_root_ = nullptr;
        mmap_handle_ = nullptr;
    }

    // Remap the partition to get updated contents
    esp_err_t err = esp_partition_mmap(partition_, 0, partition_->size, ESP_PARTITION_MMAP_DATA, (const void**)&mmap_root_, &mmap_handle_);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to mmap assets partition: %s", esp_err_to_name(err));
        return false;
    }

    // Validate magic number at start of partition
    const uint32_t* header_magic = reinterpret_cast<const uint32_t*>(mmap_root_);
    if (*header_magic != ASSETS_HEADER_MAGIC) {
        ESP_LOGE(TAG, "Invalid assets header magic: expected 0x%08X, got 0x%08X", ASSETS_HEADER_MAGIC, *header_magic);
        return false;
    }

    // Parse metadata: checksum, number of files
    const uint32_t stored_chksum = *(reinterpret_cast<const uint32_t*>(mmap_root_ + 4));
    const uint32_t stored_files = *(reinterpret_cast<const uint32_t*>(mmap_root_ + 8));
    const size_t stored_len = 12 + sizeof(mmap_assets_table) * stored_files;

    // Calculate and validate checksum
    auto start_time = esp_timer_get_time();
    uint32_t calculated_checksum = CalculateChecksum(mmap_root_ + 12, stored_len);
    auto end_time = esp_timer_get_time();
    ESP_LOGI(TAG, "Checksum calculation took %lld ms", (end_time - start_time) / 1000);

    if (calculated_checksum != stored_chksum) {
        ESP_LOGE(TAG, "Calculated checksum (0x%lx) does not match stored checksum (0x%lx)", calculated_checksum, stored_chksum);
        return false;
    }

    // Clear existing asset map
    assets_.clear();

    // Build asset index
    for (uint32_t i = 0; i < stored_files; ++i) {
        const auto item = reinterpret_cast<const mmap_assets_table*>(mmap_root_ + 12 + i * sizeof(mmap_assets_table));
        const std::string name(item->asset_name);

        Asset asset{
            .size = static_cast<size_t>(item->asset_size),
            .offset = static_cast<size_t>(12 + sizeof(mmap_assets_table) * stored_files + item->asset_offset)
        };

        // Validate each asset's magic bytes
        const char* data = reinterpret_cast<const char*>(mmap_root_ + asset.offset);
        if (data[0] != 'Z' || data[1] != 'Z') {
            ESP_LOGE(TAG, "Asset '%s' has invalid magic bytes (%02x%02x)", name.c_str(), data[0], data[1]);
            return false;
        }

        assets_[name] = asset;
    }

    ESP_LOGI(TAG, "Successfully applied %u assets.", stored_files);
    return true;
}

