bool ReadSerialFromEfuse(std::string& serial_number) {
    const size_t SERIAL_LEN = 16; // Adjust according to your efuse block layout
    uint8_t raw_data[SERIAL_LEN] = {0};

    esp_err_t err = esp_efuse_read_field_blob(ESP_EFUSE_USER_DATA, raw_data, sizeof(raw_data) * 8);
    if (err != ESP_OK) {
        ESP_LOGE("OTA", "Failed to read serial from eFuse: %s", esp_err_to_name(err));
        return false;
    }

    char hex_str[SERIAL_LEN * 2 + 1];
    for (int i = 0; i < SERIAL_LEN; ++i) {
        sprintf(&hex_str[i*2], "%02x", raw_data[i]);
    }
    serial_number = std::string(hex_str);

    return !serial_number.empty();
}
