```cpp
std::string Ota::GenerateActivationPayload(const std::string& challenge) {
    if (!has_serial_number_) {
        return "{}";
    }

    std::string hmac_hex;

#ifdef SOC_HMAC_SUPPORTED
    uint8_t hmac_result[32]; // SHA-256 output
    esp_err_t ret = esp_hmac_calculate(HMAC_KEY0,
                                       reinterpret_cast<const uint8_t*>(challenge.data()),
                                       challenge.size(),
                                       hmac_result);

    if (ret != ESP_OK) {
        ESP_LOGE("OTA", "HMAC calculation failed: %s", esp_err_to_name(ret));
        return "{}";
    }

    char buffer[3];
    for (size_t i = 0; i < sizeof(hmac_result); ++i) {
        sprintf(buffer, "%02x", hmac_result[i]);
        hmac_hex += buffer;
    }
#endif

    cJSON* payload = cJSON_CreateObject();
    cJSON_AddStringToObject(payload, "algorithm", "hmac-sha256");
    cJSON_AddStringToObject(payload, "serial_number", serial_number_.c_str());
    cJSON_AddStringToObject(payload, "challenge", challenge.c_str());
    cJSON_AddStringToObject(payload, "hmac", hmac_hex.c_str());

    char* json_str = cJSON_PrintUnformatted(payload);
    std::string result(json_str);
    cJSON_free(json_str);
    cJSON_Delete(payload);

    ESP_LOGI("OTA", "Generated activation payload: %s", result.c_str());
    return result;
}
```

