    if (update_available) {
        ESP_LOGI(TAG, "New firmware version available: %s", remote_version.c_str());
        const cJSON* firmware_url_item = cJSON_GetObjectItemCaseSensitive(json, "firmware_url");
        if (cJSON_IsString(firmware_url_item) && firmware_url_item->valuestring != nullptr) {
