    // Step 1: Initialize HTTP connection
    auto network = Board::GetInstance().GetNetwork();
    auto http = network->CreateHttp(0);
    if (!http->Open("GET", firmware_url)) {
        ESP_LOGE(TAG, "Failed to open HTTP connection");
        return false;
    }

    if (http->GetStatusCode() != 200) {
        ESP_LOGE(TAG, "Failed to get firmware, status code: %d", http->GetStatusCode());
        http->Close();
        return false;
    }

    size_t content_length = http->GetBodyLength();
    if (content_length == 0) {
        ESP_LOGE(TAG, "Failed to get content length");
        http->Close();
        return false;
    }

    // Step 2: Prepare OTA partition
    auto update_partition = esp_ota_get_next_update_partition(NULL);
    if (update_partition == nullptr) {
        ESP_LOGE(TAG, "Failed to get update partition");
        http->Close();
        return false;
    }

    esp_ota_handle_t update_handle = 0;
    if (esp_ota_begin(update_partition, OTA_WITH_SEQUENTIAL_WRITES, &update_handle) != ESP_OK) {
        ESP_LOGE(TAG, "Failed to begin OTA");
        esp_ota_abort(update_handle);
        http->Close();
        return false;
    }

    // Step 3: Version checking variables
    bool image_header_checked = false;
    std::string image_header;
    const size_t header_min_size = sizeof(esp_image_header_t) + sizeof(esp_image_segment_header_t) + sizeof(esp_app_desc_t);

    // Step 4: Download loop with buffering and progress tracking
    size_t total_read = 0;
    size_t recent_read = 0;
    auto last_calc_time = esp_timer_get_time();

    while (true) {
        int ret = http->Read(buffer, sizeof(buffer));
        if (ret < 0) {
            ESP_LOGE(TAG, "Failed to read HTTP data");
            esp_ota_abort(update_handle);
            http->Close();
            return false;
        }

        // Accumulate data for version check before writing anything
        if (!image_header_checked && image_header.size() < header_min_size) {
            image_header.append(buffer, ret);
        }

        // Once header has been read, validate version
        if (!image_header_checked && image_header.size() >= header_min_size) {
            esp_app_desc_t new_app_info;
            memcpy(&new_app_info,
                   image_header.data() + sizeof(esp_image_header_t) + sizeof(esp_image_segment_header_t),
                   sizeof(esp_app_desc_t));

            const char* current_version = esp_app_get_description()->version;
            ESP_LOGI(TAG, "Current version: %s, New version: %s", current_version, new_app_info.version);

            // Parse version strings
            auto parse_version = [](const std::string& v) -> std::vector<int> {
                std::vector<int> res;
                std::stringstream ss(v);
                std::string seg;
                while (std::getline(ss, seg, '.')) {
                    res.push_back(std::stoi(seg));
                }
                return res;
            };

            auto is_newer = [&](const std::string& cur, const std::string& newer) -> bool {
                auto c = parse_version(cur);
                auto n = parse_version(newer);
                for (size_t i = 0; i < std::min(c.size(), n.size()); ++i) {
                    if (n[i] > c[i]) return true;
                    else if (n[i] < c[i]) return false;
                }
                return n.size() > c.size();
            };

            if (!is_newer(current_version, new_app_info.version)) {
                ESP_LOGW(TAG, "No newer version detected, aborting upgrade.");
                esp_ota_abort(update_handle);
                http->Close();
                return false;
            }

            image_header_checked = true;

            // Write accumulated header data now
            auto err = esp_ota_write(update_handle, image_header.data(), image_header.length());
            if (err != ESP_OK) {
                ESP_LOGE(TAG, "Failed to write initial header data: %s", esp_err_to_name(err));
                esp_ota_abort(update_handle);
                http->Close();
                return false;
            }
            total_read += image_header.length();
            recent_read += image_header.length();
        }

        // For normal data after header verification
        if (image_header_checked && ret > 0) {
            auto err = esp_ota_write(update_handle, buffer, ret);
            if (err != ESP_OK) {
                ESP_LOGE(TAG, "Failed to write OTA data: %s", esp_err_to_name(err));
                esp_ota_abort(update_handle);
                http->Close();
                return false;
            }
            total_read += ret;
            recent_read += ret;
        }

        // Progress reporting logic
        if ((esp_timer_get_time() - last_calc_time >= 1000000) || (ret == 0)) {
            size_t progress = content_length ? (total_read * 100 / content_length) : 0;
            ESP_LOGI(TAG, "Progress: %u%% (%u/%u), Speed: %uB/s", progress, total_read, content_length, recent_read);
            if (callback) {
                callback(static_cast<int>(progress), recent_read);
            }
            last_calc_time = esp_timer_get_time();
            recent_read = 0;
        }

        if (ret == 0) {
            break;
        }
    }

    http->Close();

    // Finalize OTA operation
    auto err = esp_ota_end(update_handle);
    if (err != ESP_OK) {
        if (err == ESP_ERR_OTA_VALIDATE_FAILED) {
            ESP_LOGE(TAG, "Image validation failed, image is corrupted");
        } else {
            ESP_LOGE(TAG, "Failed to end OTA: %s", esp_err_to_name(err));
        }
        return false;
    }

    // Mark this partition as the one to boot from next time
    err = esp_ota_set_boot_partition(update_partition);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to set boot partition: %s", esp_err_to_name(err));
        return false;
    }

    ESP_LOGI(TAG, "OTA completed successfully. Device will reboot into new firmware.");
    return true;
}

