#include "system_info.h"

static const char *TAG = "SystemInfo";

static esp_err_t PrintTaskCpuUsage(TickType_t xTicksToWait) {
    // Estimate number of tasks (can be adjusted dynamically)
    UBaseType_t uxArraySize = uxTaskGetNumberOfTasks();
    TaskStatus_t *pxTaskStatusArray = NULL;
    volatile UBaseType_t uxCurrentNumberOfTasks;
    uint32_t ulTotalRunTime1, ulTotalRunTime2;
    uint32_t ulStatsAsPercentage;

    // Allocate memory for first snapshot
    pxTaskStatusArray = (TaskStatus_t *)malloc(uxArraySize * sizeof(TaskStatus_t));
    if (pxTaskStatusArray == NULL) {
        ESP_LOGE(TAG, "Failed to allocate memory for task status array");
        return ESP_FAIL;
    }

    // Take first snapshot
    uxCurrentNumberOfTasks = uxTaskGetSystemState(pxTaskStatusArray, uxArraySize, &ulTotalRunTime1);

    // Wait for specified period
    vTaskDelay(xTicksToWait);

    // Take second snapshot
    uxCurrentNumberOfTasks = uxTaskGetSystemState(pxTaskStatusArray, uxArraySize, &ulTotalRunTime2);

    // Release allocated memory as it might have changed during delay
    free(pxTaskStatusArray);

    // Reallocate in case task count has increased
    uxArraySize = uxTaskGetNumberOfTasks();
    pxTaskStatusArray = (TaskStatus_t *)malloc(uxArraySize * sizeof(TaskStatus_t));
    if (pxTaskStatusArray == NULL) {
        ESP_LOGE(TAG, "Failed to reallocate memory for task status array");
        return ESP_FAIL;
    }

    // Get updated snapshots
    uxTaskGetSystemState(pxTaskStatusArray, uxArraySize, &ulTotalRunTime1);
    vTaskDelay(xTicksToWait);
    uxTaskGetSystemState(pxTaskStatusArray, uxArraySize, &ulTotalRunTime2);

    // Calculate delta total run time
    uint32_t ulTotalTimeElapsed = ulTotalRunTime2 - ulTotalRunTime1;

    if (ulTotalTimeElapsed > 0) {
        ESP_LOGI(TAG, "Task CPU Usage:");
        for (UBaseType_t x = 0; x < uxCurrentNumberOfTasks; x++) {
            uint32_t ulTaskRunTime = pxTaskStatusArray[x].ulRunTimeCounter;

            // Get previous run time by iterating through again or storing earlier?
            // Since we can't access previous values directly without storing them,
            // we assume this version gets called periodically or uses stored state elsewhere.
            // As per FreeRTOS docs, better approach is to store previous values.

            // But since no persistent storage assumed here, we'll proceed assuming fresh calc every call.

            ulStatsAsPercentage = (ulTaskRunTime * 100UL) / ulTotalTimeElapsed;
            if (ulStatsAsPercentage > 0) {
                ESP_LOGI(TAG, "\t%s\t\t%u%%", pxTaskStatusArray[x].pcTaskName, ulStatsAsPercentage);
            }
        }
    } else {
        ESP_LOGW(TAG, "No measurable CPU activity detected.");
    }

    free(pxTaskStatusArray);
    return ESP_OK;
}

