#### 3. **PCM to Opus Encoding Loop Inside Real-Time Task**

Structure of the encoding loop that runs inside a dedicated FreeRTOS task, fetching raw PCM frames, encoding them into Opus format, and storing encoded packets safely.

```cpp
void EncodeWakeWordDataTask(void* pvParameters) {
    auto* instance = static_cast<AfeWakeWord*>(pvParameters);
    OpusEncoder* encoder = opus_encoder_create(SAMPLE_RATE, CHANNELS, OPUS_APPLICATION_VOIP, &error);
    opus_encoder_ctl(encoder, OPUS_SET_BITRATE(BITRATE));
    opus_encoder_ctl(encoder, OPUS_SET_COMPLEXITY(COMPLEXITY));

    while (true) {
        std::unique_lock<std::mutex> lock(instance->wake_word_mutex_);
        instance->wake_word_cv_.wait(lock, [instance]() {
            return !instance->wake_word_pcm_.empty();
        });

        auto pcm_frame = std::move(instance->wake_word_pcm_.front());
        instance->wake_word_pcm_.pop_front();
        lock.unlock();

        std::vector<uint8_t> opus_packet(MAX_PACKET_SIZE);
        int encoded_bytes = opus_encode(encoder, pcm_frame.data(), FRAME_SIZE, opus_packet.data(), MAX_PACKET_SIZE);

        if (encoded_bytes > 0) {
            opus_packet.resize(encoded_bytes);
            std::lock_guard<std::mutex> write_lock(instance->wake_word_mutex_);
            instance->wake_word_opus_.push_back(std::move(opus_packet));
        }
    }

    opus_encoder_destroy(encoder);
    vTaskDelete(nullptr);
}
```

