bool CustomWakeWord::ParseWakenetModelConfig() {
    void* ptr = nullptr;
    size_t size = 0;

    // Attempt to load asset data
    if (!GetAssetData("wakeword_config.json", ptr, size)) {
        ESP_LOGE(TAG, "Failed to get wakeword_config.json");
        return false;
    }

    // Parse JSON content
    cJSON* root = cJSON_ParseWithLength(static_cast<char*>(ptr), size);
    if (root == nullptr) {
        ESP_LOGE(TAG, "Invalid JSON format in wakeword_config.json");
        return false;
    }

    // Get model name
    cJSON* model_item = cJSON_GetObjectItem(root, "model");
    if (!cJSON_IsString(model_item)) {
        ESP_LOGE(TAG, "Missing or invalid 'model' field in config");
        cJSON_Delete(root);
        return false;
    }
    model_name_ = std::string(model_item->valuestring);
    ESP_LOGI(TAG, "Loaded model: %s", model_name_.c_str());

    // Get commands list
    cJSON* commands = cJSON_GetObjectItem(root, "commands");
    if (!cJSON_IsArray(commands)) {
        ESP_LOGE(TAG, "Missing or invalid 'commands' array in config");
        cJSON_Delete(root);
        return false;
    }

    const int command_count = cJSON_GetArraySize(commands);
    if (command_count <= 0) {
        ESP_LOGW(TAG, "No commands found in configuration");
        cJSON_Delete(root);
        return true; // Not necessarily an error
    }

    commands_.clear();
    commands_.reserve(command_count);

    for (int i = 0; i < command_count; ++i) {
        cJSON* cmd = cJSON_GetArrayItem(commands, i);
        if (cJSON_IsString(cmd)) {
            commands_.emplace_back(cmd->valuestring);
            ESP_LOGD(TAG, "Parsed command: %s", cmd->valuestring);
        } else {
            ESP_LOGW(TAG, "Skipping non-string item in commands array at index %d", i);
        }
    }

    cJSON_Delete(root);
    return true;
}

