#### 3. Frame Capture with Buffer Management
This pattern demonstrates capturing a frame from the camera using V4L2 queue/dequeue logic and copying it into PSRAM for further processing or display.

```cpp
bool Esp32Camera::Capture() {
    if (!streaming_on_ || video_fd_ < 0) {
        return false;
    }

    for (int i = 0; i < 3; i++) {
        struct v4l2_buffer buf = {};
        buf.type = V4L2_BUF_TYPE_VIDEO_CAPTURE;
        buf.memory = V4L2_MEMORY_MMAP;
        if (ioctl(video_fd_, VIDIOC_DQBUF, &buf) != 0) {
            ESP_LOGE(TAG, "VIDIOC_DQBUF failed");
            return false;
        }

        if (i == 2) {
            if (frame_.data) {
                heap_caps_free(frame_.data);
                frame_.data = nullptr;
                frame_.format = 0;
            }
            frame_.len = buf.bytesused;
            frame_.data = (uint8_t*)heap_caps_malloc(frame_.len, MALLOC_CAP_SPIRAM | MALLOC_CAP_8BIT);
            if (!frame_.data) {
                ESP_LOGE(TAG, "alloc frame copy failed");
                ioctl(video_fd_, VIDIOC_QBUF, &buf);
                return false;
            }

            memcpy(frame_.data, mmap_buffers_[buf.index].start,
                   MIN(mmap_buffers_[buf.index].length, frame_.len));

            frame_.format = sensor_format_;
        }

        if (ioctl(video_fd_, VIDIOC_QBUF, &buf) != 0) {
            ESP_LOGE(TAG, "VIDIOC_QBUF failed");
        }
    }

    // Display preview image here...
    return true;
}
```

