                size_t newline_pos = data_buffer.decoded_text->find('\n');

                if (newline_pos != std::string::npos) {
                    wifi_ssid = data_buffer.decoded_text->substr(0, newline_pos);
                    wifi_password = data_buffer.decoded_text->substr(newline_pos + 1);

                    // Save credentials
                    auto& ssid_manager = SsidManager::GetInstance();
                    ssid_manager.AddSsid(wifi_ssid, wifi_password);
                    ESP_LOGI(kLogTag, "WiFi credentials saved successfully");

                    // Update UI/display
                    display->ShowMessage("Connected to WiFi");

                    // Exit configuration mode
                    wifi_manager->StopConfigAp();

                    break; // Exit loop after success
                } else {
