bool MqttProtocol::SendAudio(std::unique_ptr<AudioStreamPacket> packet) {
    // Step 1: Input validation
    if (!packet || !udp_ || !udp_->IsConnected()) {
        return false;
    }

    // Step 2: Acquire thread-safe access
    std::lock_guard<std::mutex> lock(channel_mutex_);

    // Step 3: Increment and get current sequence number
    uint32_t seq_num = local_sequence_++;

    // Step 4: Prepare nonce components
    uint32_t timestamp = packet->timestamp;
    size_t payload_size = packet->payload.size();

    // Construct nonce string: [seq][ts][size] as 8-char hex each
    std::ostringstream nonce_stream;
    nonce_stream << std::setfill('0') << std::hex
                 << std::setw(8) << seq_num
                 << std::setw(8) << timestamp
                 << std::setw(8) << payload_size;

    std::string nonce_hex_str = nonce_stream.str();

    // Convert hex string to bytes (128 bits / 16 bytes total)
    std::vector<uint8_t> nonce_bytes(16, 0);
    for (size_t i = 0; i < nonce_hex_str.length(); i += 2) {
        std::string byteString = nonce_hex_str.substr(i, 2);
        nonce_bytes[i / 2] = static_cast<uint8_t>(std::stoi(byteString, nullptr, 16));
    }

    // Step 5: Set up AES-CTR parameters
    unsigned char nonce_counter[16];
    unsigned char stream_block[16];
    size_t nc_off = 0;

    memcpy(nonce_counter, nonce_bytes.data(), sizeof(nonce_counter));
    memset(stream_block, 0, sizeof(stream_block));

    // Output buffer for encrypted data
    std::vector<uint8_t> encrypted_payload(packet->payload.size());

    // Perform encryption
    int ret = mbedtls_aes_crypt_ctr(
        &aes_ctx_,
        packet->payload.size(),
        &nc_off,
        nonce_counter,
        stream_block,
        packet->payload.data(),
        encrypted_payload.data()
    );

    if (ret != 0) {
        return false; // Encryption failed
    }

    // Step 6: Transmit over UDP
    bool result = udp_->Send(encrypted_payload.data(), encrypted_payload.size());

    return result;
}

